package org.mage.test.cards.copy;

import mage.constants.PhaseStep;
import mage.constants.Zone;
import org.junit.Test;
import org.mage.test.serverside.base.CardTestPlayerBase;

/**
 * @author TheElk801
 */
public class EstridsInvocationTest extends CardTestPlayerBase {

    @Test
    public void testSecondUpkeepActivation() {
        // Test that Estrid's Invocation doesn't crash on second upkeep activation

        // Enchantment that gives +1/+1 to creatures you control
        addCard(Zone.BATTLEFIELD, playerA, "Glorious Anthem", 1);
        addCard(Zone.BATTLEFIELD, playerA, "Island", 3);
        addCard(Zone.HAND, playerA, "Estrid's Invocation", 1);

        castSpell(1, PhaseStep.PRECOMBAT_MAIN, playerA, "Estrid's Invocation");
        setChoice(playerA, true); // choose to copy
        setChoice(playerA, "Glorious Anthem"); // choose what to copy

        // First upkeep - activate the flicker ability
        setChoice(playerA, true); // choose to exile and return
        setChoice(playerA, true); // choose to copy again
        setChoice(playerA, "Glorious Anthem"); // copy the anthem again

        // Second upkeep - activate again (this was crashing)
        setChoice(playerA, true); // choose to exile and return
        setChoice(playerA, true); // choose to copy again
        setChoice(playerA, "Glorious Anthem"); // copy the anthem again

        setStopAt(5, PhaseStep.PRECOMBAT_MAIN);
        execute();

        assertPermanentCount(playerA, "Glorious Anthem", 2);
        assertLife(playerA, 20);
    }
}

