        // Attach Inferno Fist to Lion
        castSpell(1, PhaseStep.PRECOMBAT_MAIN, playerA, "Inferno Fist", "Silvercoat Lion");

        // Cast Estrid's Invocation, copy Inferno Fist
        castSpell(1, PhaseStep.PRECOMBAT_MAIN, playerA, "Estrid's Invocation");
        setChoice(playerA, true); // choose to copy
        setChoice(playerA, "Inferno Fist"); // choose what to copy
        setChoice(playerA, "Silvercoat Lion"); // target for the copy

        // First upkeep - activate flicker
        setChoice(playerA, true); // exile and return
        setChoice(playerA, true); // copy again
        setChoice(playerA, "Inferno Fist"); // choose what to copy
        setChoice(playerA, "Silvercoat Lion"); // target for the copy

        // Second upkeep - activate again
        setChoice(playerA, true); // exile and return
        setChoice(playerA, true); // copy again
        setChoice(playerA, "Inferno Fist"); // choose what to copy
        setChoice(playerA, "Silvercoat Lion"); // target for the copy

